create table categories (
  id INT,
  name VARCHAR(50),
  description TEXT,
  price DECIMAL(7,2)
);
---------------------------------------------------------------------
create table product (
  id INT,
  name VARCHAR(50),
  description TEXT,
  stock INT,
  price DECIMAL(7,2),
  category_id int references categories(id)
);
